const plan = {
  packet_family: 'downstream_resource_prep_plan',
  replay_reference: { workflow: 'WF-023', dossier_id: $json.dossier_id, timestamp: new Date().toISOString() },
  asset_classes: [
    { id: 'thumbnail', owner: 'CWF-410', priority: 'high' },
    { id: 'visual_assets', owner: 'CWF-420', priority: 'high' },
    { id: 'audio_optimization', owner: 'CWF-430', priority: 'medium' },
    { id: 'metadata_distribution', owner: 'CWF-510', priority: 'medium' }
  ],
  sequencing: ['CWF-410', 'CWF-420', 'CWF-430', 'CWF-440', 'CWF-510', 'CWF-520', 'CWF-530']
};
return [{ json: { ...$json, prep_plan: plan } }];

const plan = $json.prep_plan || {};
const errs = [];
if (!Array.isArray(plan.asset_classes) || plan.asset_classes.length === 0) errs.push('asset_classes missing');
if (!Array.isArray(plan.sequencing) || plan.sequencing.length === 0) errs.push('sequencing missing');
if (!plan.replay_reference) errs.push('replay_reference missing');
if (errs.length) throw new Error('WF-023 validation failed: ' + errs.join('; '));
return [{ json: { workflow_id: 'WF-023', status: 'SUCCESS', output_packet_family: 'downstream_resource_prep_plan', downstream_resource_prep_plan: plan } }];
